<body>

    <div id="guagua-raw-data">$1$2</div>
    <div id="dream-render-target"></div>

    <script>
    (function() {
        const rawEl = document.getElementById('guagua-raw-data');
        if (!rawEl) return;
        const rawContent = rawEl.innerHTML;
        const target = document.getElementById('dream-render-target');

        const extractTag = (tag) => {
            const regex = new RegExp(`<${tag}(?:\\s[^>]*)?>([\\s\\S]*?)<\\/${tag}>`, 'i');
            const match = rawContent.match(regex);
            return match ? match[1].trim() : null;
        };

        const meow = extractTag('meow_FM');
        const branchesRaw = extractTag('branches');

        const hasSummary = !!meow;
        let hasBranches = false;
        let branchLines = [];

        if (branchesRaw) {
            branchLines = branchesRaw.replace(/<br\s*\/?>/gi, '\n')
                                     .split('\n')
                                     .map(l => l.trim())
                                     .filter(l => l.length > 0);
            if (branchLines.length > 0) hasBranches = true;
        }

        if (!hasSummary && !hasBranches) return;

        const showTabs = hasSummary && hasBranches;
        let headerHTML = '';
        if (showTabs) {
            headerHTML = `
                <div class="tab-header">
                    <button class="tab-button active" onclick="switchTab('summary')"><span>梦境摘要</span></button>
                    <button class="tab-button" onclick="switchTab('branch')"><span>剧情分支</span></button>
                </div>
            `;
        }

        let summaryHTML = '';
        if (hasSummary) {
            const sub = (txt, t) => {
                const m = txt.match(new RegExp(`<${t}>([\\s\\S]*?)<\\/${t}>`, 'i'));
                return m ? m[1].trim() : '';
            };
            const sNum = sub(meow, 'notes') || 'LOG';
            const sTime = sub(meow, 'time') || '未知';
            const sScene = sub(meow, 'scene') || '未知';
            const sPlot = sub(meow, 'plot') || '';

            const iconUser = `<svg class="meta-icon" viewBox="0 0 24 24"><path d="M19.349,3.665H4.651A2.651,2.651,0,0,0,2.005,6.316V21.135a.865.865,0,0,0,1.3.748l8.7-5.523,8.7,5.523a.865.865,0,0,0,1.3-.748V6.316A2.651,2.651,0,0,0,19.349,3.665Zm-.865,15.722-7.975-5.064a.865.865,0,0,0-1.018,0L3.743,19.387V6.316a.9.9,0,0,1,.9-.9H19.349a.9.9,0,0,1,.9.9Z"/></svg>`;
            const iconTime = `<svg class="meta-icon" viewBox="0 0 24 24"><path d="M19,4h-1V2h-2v2H8V2H6v2H5C3.89,4,3.01,4.9,3.01,6L3,20c0,1.1,0.89,2,2,2h14c1.1,0,2-0.9,2-2V6C21,4.9,20.1,4,19,4z M19,20H5V10h14V20z"/></svg>`;
            const iconLoc = `<svg class="meta-icon" viewBox="0 0 24 24"><path d="M12,2C8.13,2,5,5.13,5,9c0,5.25,7,13,7,13s7-7.75,7-13C19,5.13,15.87,2,12,2z M12,11.5c-1.38,0-2.5-1.12-2.5-2.5s1.12-2.5,2.5-2.5s2.5,1.12,2.5,2.5S13.38,11.5,12,11.5z"/></svg>`;

            const isActive = showTabs ? 'active' : (hasSummary ? 'active' : '');
            const displayStyle = showTabs ? '' : 'display: block;';

            summaryHTML = `
                <div id="tab-content-summary" class="tab-content ${isActive}" style="${displayStyle}">
                    <div class="summary-meta">
                        <div class="meta-item">${iconUser}<span class="meta-text">${sNum}</span></div>
                        <div class="meta-item">${iconTime}<span class="meta-text">${sTime}</span></div>
                        <div class="meta-item">${iconLoc}<span class="meta-text">${sScene}</span></div>
                    </div>
                    <p class="summary-plot">${sPlot}</p>
                </div>
            `;
        }

        let branchHTML = '';
        if (hasBranches) {
            const btns = branchLines.map((opt, idx) => {
                const safeOpt = opt.replace(/'/g, "\\'");
                return `
                    <div class="branch-option" onclick="trySend('${safeOpt}')">
                        <span class="option-number">${idx + 1}</span>
                        <span class="option-text">${opt}</span>
                    </div>`;
            }).join('');

            const isActive = showTabs ? '' : 'active';
            const displayStyle = showTabs ? '' : 'display: block;';

            branchHTML = `
                <div id="tab-content-branch" class="tab-content ${isActive}" style="${displayStyle}">
                    <div class="branch-options">${btns}</div>
                </div>
            `;
        }

        const cardClass = showTabs ? 'dream-card has-header' : 'dream-card no-header';

        const card = document.createElement('div');
        card.className = 'dream-system-container';
        card.innerHTML = `
            <div class="${cardClass}">
                ${headerHTML}
                ${summaryHTML}
                ${branchHTML}
            </div>
        `;
        target.appendChild(card);

        window.switchTab = (tabName) => {
            if (!showTabs) return;
            const idx = tabName === 'summary' ? 0 : 1;
            document.querySelectorAll('.tab-button').forEach(b => b.classList.remove('active'));
            document.querySelectorAll('.tab-button')[idx].classList.add('active');

            document.querySelectorAll('.tab-content').forEach(c => {
                c.classList.remove('active');
                c.style.display = '';
            });
            document.getElementById(`tab-content-${tabName}`).classList.add('active');
        };

        window.trySend = (text) => {
            let ta = document.getElementById('send_textarea');
            let btn = document.getElementById('send_but');
            if (!ta && window.parent && window.parent.document) {
                try {
                    ta = window.parent.document.getElementById('send_textarea');
                    btn = window.parent.document.getElementById('send_but');
                } catch(e) {}
            }
            if (ta) {
                ta.value = text;
                ta.dispatchEvent(new Event('input', { bubbles: true }));
                if (btn) btn.click();
            }
        };

    })();
    </script>
</body>
</html>
